(function() {
    /*======== 版本更新日志 ========*/
    /*
     * 作者：sjshb57
     * GitHub：https://github.com/sjshb57/legado-57
     *
     * [v2.8.5] 第三十四次修改 - 优化代码
     * - 优化部分匹配标点/规则
     * - 修复白名单无法生效的问题
     * - 修复部分使用的不兼容的语法格式
     * - 修复造成出现中文数字的转换错误
     * - 修复注释过长造成的Rhino截断执行
     * - 优化步骤0逻辑策略，修复回溯问题
     * - 修复索引字符串异常，使用charAt(i)
     */

    // ========= 1. 功能文档 =========
    /*
     * 功能概述：
     * 本脚本是一个高级中文数字标题转换工具，专门用于处理各种格式的中文数字标题，
     * 将其转换为统一的阿拉伯数字格式，同时提供多种智能处理选项。
     *
     * 主要功能：
     * 1. 全面支持简繁体中文数字转换（零-萬）
     * 2. 智能空格处理（自动补全章节号与内容间的空格）
     * 3. 标点符号统一清理（入口处集中处理，覆盖所有标题类型）
     * 4. 特殊章节处理（『第零章』→『序章』）
     * 5. 支持纯数字标题转换（『1 内容』→『第1章 内容』）
     * 6. 无标识符标题兼容（『第一百标题』→『第100章 标题』）
     * 7. 多章节标识符适配（章/节/回/集等）
     * 8. 灵活的配置系统（可自定义删除的标点字符集、默认章节后缀等）
     * 9. 标识符白名单保护（指定标识符不被 defaultSuffix 覆盖）
     * 10. 括号内容清理（非黑名单字符保留并转为半角格式，其余内容随整体删除）
     *
     */

    // ========= 2. 配置系统 =========
    /*
     * 可通过 Config 对象调整以下配置项：
     *
     * punctuationsToRemove {string} 默认 '.。,，'
     *   需要统一删除的标点字符集（作为正则字符类使用）。
     *   在 processTitle 入口处一次性全文删除，覆盖所有标题类型、所有位置。
     *   示例：'.。,，' → 删除英文句点、中文句号、英文逗号、中文逗号
     *
     */
    const Config = {
        punctuationsToRemove: '.。,，', // 需要统一删除的标点字符集
        convertZeroToPreface: false, // 是否将零值转换为"序"
        defaultSuffix: '章', // 覆盖使用此章节标识后缀
        preserveSuffixes: '卷次' // 白名单：这些标识符不被 defaultSuffix 覆盖，原样保留（空字符串则全部替换）
    };

    // ====== 3. 正则表达式系统 ======
    /*
     * Regex 对象封装所有预编译的正则表达式，避免重复编译，提升性能。
     * 其中标点相关的正则均根据 Config.punctuationsToRemove 动态构建。
     *
     * 注意：chapter 正则的标识符字符类由默认标识符 + preserveSuffixes 动态合并，
     * 确保白名单字符（如「次」）能被正确捕获并保留。
     * chinesePunctuation 不含半角括号，括号后需自动补空格。
     */
    var escaped = Config.punctuationsToRemove.replace(/[-\]\\^[\/.*+?()|{}$]/g, '\\$&');
    var baseSuffixes = '章节回集卷部篇话讲段';
    var extraSuffixes = '';
    for (var si = 0; si < Config.preserveSuffixes.length; si++) {
        var sch = Config.preserveSuffixes.charAt(si);
        if (baseSuffixes.indexOf(sch) < 0 && extraSuffixes.indexOf(sch) < 0) extraSuffixes += sch;
    }
    var Regex = {
        patterns: {
            chinesePunctuation: /^[：、；？！。…]/,
            chapter: new RegExp('^第(\\d+|[零〇一二三四五六七八九十百千两万壹贰叁肆伍陆柒捌玖拾佰仟萬貳參陸]+)([' + baseSuffixes + extraSuffixes + ']?)(.*)'),
            digitalChapter: /^(\d+)\s*(.*)/,
            allPunctuations: new RegExp('[' + escaped + ']', 'g'),
            leadingPunctuations: new RegExp('^[\\s' + escaped + ']+')
        }
    };

    // ======= 4. 数字转换系统 =======
    /*
     * NumberConverter 负责将中文数字字符串转换为阿拉伯数字。
     *
     * map 映射表覆盖：
     *   基础数字：零〇一二两三四五六七八九（含同义词）
     *   单位数字：十百千万（进位单位）
     *   财务大写：壹贰叁肆伍陆柒捌玖拾佰仟萬
     *   繁体数字：貳參陸
     *
     * convert 算法（逐字扫描，O(n) 时间，O(1) 空间）：
     *   维护两个变量：
     *     total - 已完成计算的累计值
     *     temp  - 当前待与进位单位相乘的临时值
     *
     *   规则：
     *   - 遇到进位单位（十/百/千/万）：
     *       temp 若为0（如『十二』的『十』前无数字），按1处理
     *       temp × 单位 → 累加到 total，temp 归零
     *   - 遇到普通数字字符：temp += 数值
     *   - 循环结束后：total + temp 即为最终结果
     *
     */
    const NumberConverter = {
        map: {
            // 基础数字
            '零': 0,
            '〇': 0,
            '一': 1,
            '二': 2,
            '两': 2,
            '三': 3,
            '四': 4,
            '五': 5,
            '六': 6,
            '七': 7,
            '八': 8,
            '九': 9,
            // 进位单位
            '十': 10,
            '百': 100,
            '千': 1000,
            '万': 10000,
            // 财务大写
            '壹': 1,
            '贰': 2,
            '叁': 3,
            '肆': 4,
            '伍': 5,
            '陆': 6,
            '柒': 7,
            '捌': 8,
            '玖': 9,
            '拾': 10,
            '佰': 100,
            '仟': 1000,
            '萬': 10000,
            // 繁体
            '貳': 2,
            '參': 3,
            '陸': 6
        },

        convert: function(chineseNum) {
            var total = 0;
            var temp = 0;

            for (var i = 0; i < chineseNum.length; i++) {
                var val = this.map[chineseNum.charAt(i)]; // Rhino 兼容：用 charAt(i) 替代 [i]
                if (val === 10 || val === 100 || val === 1000 || val === 10000) {
                    // 遇到进位单位：temp 为 0 时视为隐含的 1（如『十二』→12）
                    temp = (temp === 0 ? 1 : temp) * val;
                    total += temp;
                    temp = 0;
                } else if (val !== undefined) {
                    temp += val;
                }
            }

            return total + temp;
        }
    };

    // ======== 5. 主处理函数 ========

    function processTitle(title) {

        // --- 步骤0：括号内容处理 ---
        // 黑名单字符集：含有以下这些字符的括号内容进行整体删除。
        // 拆为两步处理（0a闭合/0b未闭合），避免 g 标志 + $ 锚定的回溯问题：
        //   - 内容命中黑名单字符时，整体删除
        //   - 其他内容替换为「 (内容) 」（半角括号，两侧补空格），未闭合括号自动补右括号
        var bracketBlacklist = /[票更快祝新迎章订架求免]/;
        title = title.replace(/[（(]([^）)]*)[）)]/g, function(_, inner) {
            return bracketBlacklist.test(inner) ? '' : ' (' + inner + ') ';
        });
        title = title.replace(/[（(]([^）)]*)$/, function(_, inner) {
            return bracketBlacklist.test(inner) ? '' : ' (' + inner + ')';
        });
        title = title.replace(/ {2,}/g, ' ').replace(/^ +| +$/g, '');
        const stripped = title.replace(/^[\d.]+/, '').trim();
        if (stripped && title.match(/^\d+\.\d/)) return stripped;

        // --- 步骤1：统一标点预处理 ---
        // 对 punctuationsToRemove 中的标点一次性全文删除，覆盖所有标题类型和所有位置。
        title = title.replace(Regex.patterns.allPunctuations, '');

        // --- 步骤2：纯数字标题处理 ---
        // 匹配以数字开头的标题，清理数字后的前导空白，统一转换为「第N章 内容」格式。
        // 标点已在步骤1全文清理，此处仅需 trim 去除前导空白。
        var digitalMatch = title.match(Regex.patterns.digitalChapter);
        if (digitalMatch) {
            var num = digitalMatch[1];
            var cleanedContent = digitalMatch[2].trim();
            return cleanedContent ?
                '第' + num + Config.defaultSuffix + ' ' + cleanedContent :
                '第' + num + Config.defaultSuffix;
        }

        // --- 步骤3：非「第」开头标题处理 ---
        // 不以「第」开头则无章节号可转换，直接返回。
        if (title.charAt(0) !== '第') {
            return title;
        }

        // --- 步骤4：正则匹配标题各部分 ---
        // 提取章节标题的三个组成部分：
        //   chineseNum     - 中文或阿拉伯数字字符串（如「壹佰贰拾叁」）
        //   originalSuffix - 章节标识符（如「节」，可能为空字符串）
        //   titlePart      - 标题内容（如「 内容」，含原始前导空白与标点）
        // 若匹配失败（如「第abc章」），原样返回。
        var match = title.match(Regex.patterns.chapter);
        if (!match) return title;

        var chineseNum = match[1];
        var originalSuffix = match[2];
        var titlePart = match[3] || '';

        // 无标识符时，若 titlePart 为以下标识符开头，则原样返回（避免误匹配）
        if (!originalSuffix && /^[季年月日周天期次]/.test(titlePart.replace(/^\s+/, ''))) {
            return title;
        }

        // suffix：白名单内的标识符原样保留，其余统一使用 defaultSuffix。
        var suffix = (originalSuffix && Config.preserveSuffixes.indexOf(originalSuffix) >= 0) ?
            originalSuffix :
            Config.defaultSuffix;

        // 清理章节标识符后的前导空白（标点已在步骤1全文清理）
        var cleanTitlePart = titlePart.trim();

        // --- 步骤5：数字转换 ---
        // chineseNum 为阿拉伯数字时直接使用，否则调用 NumberConverter.convert 转换。
        var number = /^\d+$/.test(chineseNum) ? chineseNum : NumberConverter.convert(chineseNum);

        // --- 步骤6：零值特殊处理 ---
        // convertZeroToPreface=true 且转换结果为 0 时，
        // 将「第零章」形式转换为「序章」：number 清空，suffix 前缀加「序」。
        if (number === 0 && Config.convertZeroToPreface) {
            number = '';
            suffix = '序' + suffix;
        }

        // --- 步骤7：空格处理与结果组装 ---
        // 始终自动补空格，但中文标点开头的内容除外（如「：内容」不需补空格）。
        if (cleanTitlePart) {
            var shouldAddSpace = !Regex.patterns.chinesePunctuation.test(cleanTitlePart);
            return '第' + number + suffix + (shouldAddSpace ? ' ' : '') + cleanTitlePart;
        }

        // 无标题时直接返回「第N章」格式
        return '第' + number + suffix;
    }

    // ========== 执行入口 ==========
    // result 是阅读软件传入的原始标题文本，processTitle 处理后返回转换结果。
    // 整体执行时间受 timeoutMillisecond（3000ms）限制。
    return processTitle(result);
})();
